import*as Browser from"@hyperjump/browser";import*as Instance from"../instance.js";import{Validation}from"../experimental.js";import{fromEpsilon,fromSchema,closure,zeroOrOne,oneOrMore,concat,union}from"../nfa.js";const id="https://json-schema.org/keyword/itemPattern",compile=async(e,r)=>{const t=[[]];let o=t[0];for await(const i of Browser.iter(e))if("string"===Browser.typeOf(i)){var n=Browser.value(i);if("*"===n)o.push(closure(o.pop()));else if("?"===n)o.push(zeroOrOne(o.pop()));else if("+"===n)o.push(oneOrMore(o.pop()));else{if("|"!==n)throw Error("Unsupported pattern syntax: "+n);o=[],t.push(o)}}else{n="array"===Browser.typeOf(i)?compile(i,r):fromSchema(await Validation.compile(i,r));o.push(await n)}return 0===Browser.length(e)?fromEpsilon():t.map(e=>e.reduce(concat)).reduce(union)},interpret=(e,r,t)=>{if("array"!==Instance.typeOf(r))return!0;let o=[];addNextState(e.start,o,[]);for(const s of Instance.iter(r)){var n=[];for(const a of o){var i=transition(a.transition,s,t);i&&addNextState(i,n,[])}o=n}return Boolean(o.find(e=>e.isEnd))},addNextState=(e,r,t)=>{if(e.epsilonTransitions.length)for(const o of e.epsilonTransitions)t.find(e=>e===o)||(t.push(o),addNextState(o,r,t));else r.push(e)},transition=(e,r,t)=>{for(const o in e)if(Validation.interpret(o,r,t))return e[o]};export default{id:id,compile:compile,interpret:interpret};